Pattern.Snippet:
```typescript
// eslint.config.ts
import tseslint from 'typescript-eslint';
import unicorn from 'eslint-plugin-unicorn';
import importPlugin from 'eslint-plugin-import';
import prettierConfig from 'eslint-config-prettier/flat';

export default tseslint.config(
    // --- language options ---------------------------------------------------
    {
        files: ['**/*.{ts,tsx}'],
        languageOptions: {
            parserOptions: {
                project: './tsconfig.json',
                tsconfigRootDir: import.meta.dirname,
            },
        },
    },

    // --- preset: typescript-eslint -----------------------------------------
    // Preset 'warn' entries normalized: every kept rule is 'error'; the rest are 'off'.
    ...tseslint.configs.recommended,
    {
        rules: {
            // Off â€” duplicates tsc --strict.
            '@typescript-eslint/no-unused-vars': 'off',

            // Autofix; trivially kept:
            '@typescript-eslint/consistent-type-imports': ['error', { prefer: 'type-imports' }],
            '@typescript-eslint/no-import-type-side-effects': 'error',
            '@typescript-eslint/prefer-as-const': 'error',

            // No autofix. Catches `await` on non-Promise values, which silently resolves to itself
            // and is almost always a bug. tsc allows it because the type is legal.
            '@typescript-eslint/await-thenable': 'error',

            // No autofix. Catches floating promises that lose errors and break ordering.
            // tsc allows void-returning calls, so this gap is unique to the lint layer.
            '@typescript-eslint/no-floating-promises': 'error',
        },
    },

    // --- preset: unicorn (autofix-capable subset only) ---------------------
    unicorn.configs['flat/recommended'],
    {
        rules: {
            // Off â€” opinionated naming, owned by code review.
            'unicorn/filename-case': 'off',
            'unicorn/prevent-abbreviations': 'off',

            // Autofix; kept:
            'unicorn/prefer-node-protocol': 'error',
            'unicorn/prefer-string-starts-ends-with': 'error',
            'unicorn/prefer-array-some': 'error',
        },
    },

    // --- import order (autofixable) ----------------------------------------
    {
        plugins: { import: importPlugin },
        rules: {
            'import/order': ['error', {
                groups: ['builtin', 'external', 'internal', 'parent', 'sibling', 'index'],
                'newlines-between': 'always',
                alphabetize: { order: 'asc' },
            }],
        },
    },

    // --- core ESLint rules -------------------------------------------------
    {
        rules: {
            // Autofix; kept:
            'prefer-const': 'error',
            'no-var': 'error',
            'object-shorthand': ['error', 'always'],
            'prefer-template': 'error',
            'arrow-body-style': ['error', 'as-needed'],

            // Off â€” duplicates tsc.
            'no-unused-vars': 'off',
            'no-undef': 'off',
            'consistent-return': 'off',

            // Off â€” structural/design concerns owned by review and other directives.
            'complexity': 'off',
            'max-lines': 'off',
            'max-lines-per-function': 'off',
            'no-magic-numbers': 'off',
        },
    },

    // --- formatting boundary: must be LAST so it overrides any leaks -------
    // Disables every stylistic rule that may have entered via presets.
    // Formatting is owned by Prettier (npm run format).
    prettierConfig,
);
```

```json
{
    "scripts": {
        "format": "prettier --write .",
        "lint": "eslint --fix .",
        "lint:fix": "npm run format && npm run lint",
        "lint:check": "prettier --check . && eslint .",
        "typecheck": "tsc --noEmit"
    }
}
```

Anti_Pattern.Good:
```typescript
rules: {
    // Off â€” design concern, owned by code review.
    '@typescript-eslint/no-explicit-any': 'off',

    // Off â€” production logging is policy, not a lint concern; debug `console.*` is caught by review.
    'no-console': 'off',

    // No autofix. Catches floating promises that lose errors and break ordering.
    // tsc allows void-returning calls, so this gap is unique to the lint layer.
    '@typescript-eslint/no-floating-promises': 'error',

    'prefer-const': ['error', { destructuring: 'all' }],
}
```

Anti_Pattern.Bad:
```typescript
// eslint.config.ts (excerpt) â€” non-autofix rules turned on without motivation
rules: {
    'complexity': ['error', 10],
    'max-lines': ['error', 500],
    'no-magic-numbers': ['error', { ignore: [0, 1, -1] }],
    '@typescript-eslint/no-explicit-any': 'error',
    '@typescript-eslint/no-floating-promises': 'error', // no comment â€” why is this on?
}
```

Anti_Pattern.Good:
```typescript
rules: {
    // Off â€” structural limits owned by testing/vitest-rules and code review.
    'complexity': 'off',
    'max-lines': 'off',
    'no-magic-numbers': 'off',

    // Off â€” design concern owned by code review (operator decides per-call-site).
    '@typescript-eslint/no-explicit-any': 'off',

    // No autofix. Catches floating promises that lose errors and break ordering.
    // tsc allows void-returning calls, so this gap is unique to the lint layer.
    '@typescript-eslint/no-floating-promises': 'error',
}
```

Anti_Pattern.Bad:
```typescript
// src/legacy/adapter.ts â€” agent's commit
export function adapt(input: unknown) {
    // eslint-disable-next-line @typescript-eslint/no-floating-promises
    void doWork(input);
}
```

Anti_Pattern.Good:
```typescript
// The agent fixes the floating promise per the rule's motivation:
export async function adapt(input: unknown) {
    await doWork(input);
}
// OR, if the rule is genuinely wrong here, the agent stops and surfaces it
// to the operator for a config change. No source-level disable.
```

Anti_Pattern.Bad:
```typescript
// eslint.config.ts (excerpt) â€” fights with the project's Prettier config
rules: {
    'indent': ['error', 4],
    'quotes': ['error', 'single'],
    'semi': ['error', 'always'],
    'comma-dangle': ['error', 'always-multiline'],
    'max-len': ['error', { code: 100 }],
}
// .prettierrc.json says: tabWidth: 2, singleQuote: true, semi: true, trailingComma: 'all', printWidth: 80
// â†’ ESLint rewrites what Prettier just wrote, then Prettier rewrites it back. CI flickers.
```

Anti_Pattern.Good:
```typescript
import prettierConfig from 'eslint-config-prettier/flat';
export default tseslint.config(
    // ... preset(s) and project rules above ...
    prettierConfig, // MUST be last â€” disables stylistic rules from any preset
);
```

Anti_Pattern.Bad:
